9	// ─── initDb / closeDb ─────────────────────────────────────────────────────────
10	describe('initDb / closeDb', () => {
11	  it('initDb(:memory:) returns a Database instance', () => {
12	    const db = initDb(':memory:');
13	    assert.ok(db, 'should return a truthy db');
14	    closeDb();
15	  });
16	
17	  it('creates cards table', () => {
18	    const db = initDb(':memory:');
19	    const row = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='cards'").get();
20	    assert.ok(row, 'cards table should exist');
21	    closeDb();
22	  });
