2	import { getCards, createCard, updateCard, deleteCard, moveCard, NotFoundError } from '../db/queries.js';
3	import { broadcast } from '../ws/broadcaster.js';
4	
5	const router = Router();
6	
7	// GET /api/cards
8	router.get('/cards', (_req, res, next) => {
9	  try {
10	    const cards = getCards();
11	    return res.status(200).json(cards);
12	  } catch (err) {
13	    next(err);
14	  }
15	});
16	
17	// POST /api/cards
18	router.post('/cards', (req, res, next) => {
19	  const { title, assignee, column, description } = req.body ?? {};
20	  if (!title) {
21	    return res.status(400).json({ error: 'title is required' });
22	  }
23	  try {
24	    const card = createCard({ title, assignee, column, description });
25	    try { broadcast('card:created', card); } catch { /* isolate broadcast errors */ }
26	    return res.status(201).json(card);
27	  } catch (err) {
28	    next(err);
29	  }
30	});
31	
32	// PATCH /api/cards/:id
33	const CARD_UPDATE_ALLOWED = ['title', 'assignee', 'column', 'description', 'position'];
34	router.patch('/cards/:id', (req, res, next) => {
35	  const updateData = req.body ?? {};
36	  try {
37	    const card = updateCard(req.params.id, updateData);
38	    // Only broadcast when at least one recognized field was in the request body,
39	    // meaning updateCard actually performed a DB write. An empty or unrecognized-only
40	    // body causes updateCard to return the card unchanged (no DB write), so no broadcast.
41	    if (Object.keys(updateData).some(k => CARD_UPDATE_ALLOWED.includes(k))) {
42	      try { broadcast('card:updated', card); } catch { /* isolate broadcast errors */ }
43	    }
44	    return res.status(200).json(card);
45	  } catch (err) {
46	    if (err instanceof NotFoundError) {
47	      return res.status(404).json({ error: err.message });
48	    }
49	    next(err);
50	  }
51	});
52	
53	// DELETE /api/cards/:id
54	router.delete('/cards/:id', (req, res, next) => {
55	  try {
56	    deleteCard(req.params.id);
57	    try { broadcast('card:deleted', { id: req.params.id }); } catch { /* isolate */ }
58	    return res.status(204).send();
59	  } catch (err) {
60	    if (err instanceof NotFoundError) {
61	      return res.status(404).json({ error: err.message });
62	    }
63	    next(err);
64	  }
