describe('PATCH /api/cards/:id', () => {
  let server, baseUrl, wsUrl, cardId;
  before(async () => {
    initDb(':memory:');
    cardId = createCard({ title: 'Original' }).id;
    ({ server, baseUrl, wsUrl } = await startTestServerWithWs(createApp()));
